import{_ as d,o as r,c as a,a2 as e}from"./chunks/framework.DIMps2S2.js";const f=JSON.parse('{"title":"交易费用","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/trading-fees/index.md","filePath":"zh-CN/stock-trading/trading-fees/index.md"}'),o={name:"stock-trading/trading-fees/index.md"};function n(s,t,i,h,l,g){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="交易费用" tabindex="-1">交易费用 <a class="header-anchor" href="#交易费用" aria-label="Permalink to &quot;交易费用&quot;">​</a></h1><p>本章节说明长桥各市场的交易费用结构，包括港股、美股的佣金标准、平台费、监管费、印花税等组成部分，并提供详细的佣金计算示例。</p><h2 id="费用构成概览" tabindex="-1">费用构成概览 <a class="header-anchor" href="#费用构成概览" aria-label="Permalink to &quot;费用构成概览&quot;">​</a></h2><p>你在长桥买卖股票时支付的费用由多个部分组成：</p><h3 id="港股-以-10-000-hkd-的交易为例" tabindex="-1">港股（以 10,000 HKD 的交易为例） <a class="header-anchor" href="#港股-以-10-000-hkd-的交易为例" aria-label="Permalink to &quot;港股（以 10,000 HKD 的交易为例）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>费用项</th><th>收费标准</th><th>示例金额</th></tr></thead><tbody><tr><td><strong>佣金</strong></td><td>0.03%</td><td>3 HKD</td></tr><tr><td><strong>平台费</strong></td><td>固定</td><td>15 HKD</td></tr><tr><td><strong>交收费</strong></td><td>0.002%</td><td>2 HKD</td></tr><tr><td><strong>印花税</strong></td><td>0.1%</td><td>10 HKD</td></tr><tr><td><strong>其他监管费</strong></td><td>约 0.008%</td><td>不足 1 HKD</td></tr><tr><td><strong>总计</strong></td><td>约 0.14%</td><td>~30 HKD（0.3%）</td></tr></tbody></table><h3 id="美股-以-1-000-usd-的交易为例" tabindex="-1">美股（以 1,000 USD 的交易为例） <a class="header-anchor" href="#美股-以-1-000-usd-的交易为例" aria-label="Permalink to &quot;美股（以 1,000 USD 的交易为例）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>费用项</th><th>收费标准</th><th>示例金额</th></tr></thead><tbody><tr><td><strong>佣金</strong></td><td>0.0049 USD/股</td><td>取决于股数</td></tr><tr><td><strong>平台费</strong></td><td>0.005 USD/股</td><td>取决于股数</td></tr><tr><td><strong>最低费用</strong></td><td>两项都有</td><td>最少 1.99 USD</td></tr></tbody></table><p><strong>关键差异</strong>：美股按股数计费（不按金额），港股按百分比计费。</p><h2 id="本章导航" tabindex="-1">本章导航 <a class="header-anchor" href="#本章导航" aria-label="Permalink to &quot;本章导航&quot;">​</a></h2><ul><li><a href="/wiki/stock-trading/trading-fees/fee-schedule">交易收费</a> — 完整的佣金表、平台费、监管费详情</li><li><a href="/wiki/stock-trading/trading-fees/my-fees">我的费率</a> — 查看账户实际适用的个人费率</li></ul>',11)])])}const u=d(o,[["render",n]]);export{f as __pageData,u as default};
